// 筛选目标邮件（用户数据）- 周度
const inputs = $input.all();

// 计算上周时间范围
const today = new Date();
const dayOfWeek = today.getDay();
const daysToSubtract = dayOfWeek === 0 ? 13 : dayOfWeek + 6;
const lastMonday = new Date(today);
lastMonday.setDate(today.getDate() - daysToSubtract);
const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);

const formatDate = (date) => {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}${m}${d}`;
};

const weekRange = `${formatDate(lastMonday)}-${formatDate(lastSunday)}`;
const targetSubjectVariants = [
  `【${weekRange}】周度用户数据报表`,
  `周度用户数据报表 - ${weekRange}`,
];
const targetSender = "poon@gaming-panda.com";
const targetAttachments = ["游戏新用户留存数据.xlsx"];

// 筛选逻辑
const targetEmails = [];

inputs.forEach((input) => {
  const emailData = input.json;
  const subject = emailData.data?.message?.subject || emailData.subject || "";
  const sender = emailData.data?.message?.head_from?.mail_address || emailData.head_from?.mail_address || "";

  const subjectMatches = targetSubjectVariants.some(targetSubj => subject === targetSubj);
  const senderMatches = sender.toLowerCase().trim() === targetSender.toLowerCase();

  if (subjectMatches && senderMatches) {
    const attachments = emailData.data?.message?.attachments || emailData.attachments || [];
    const matchedAttachments = attachments.filter(att =>
      att.filename && targetAttachments.includes(att.filename)
    );

    if (matchedAttachments.length > 0) {
      const messageId = emailData.data?.message?.message_id || emailData.message_id;
      targetEmails.push({
        message_id: messageId,
        subject,
        sender,
        target_attachment: matchedAttachments[0],
        target_attachments: matchedAttachments,
        report_type: 'weekly',
        target_period: weekRange,
      });
    }
  }
});

return targetEmails.map(email => ({ json: email }));

